INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-9e854390-moex-00326', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司倉庫於10月20日發生大火，導致存貨全部毀損，已知10月份期初存貨為$150,000，進貨 $450,000，進貨運費$50,000，銷貨收入$900,000，銷貨運費$80,000，估計毛利率為銷貨的40%。 若採毛利率法估計，則甲公司存貨損失金額是多少？', '["$60,000", "$108,000", "$110,000", "$158,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00327', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司採定期盤存制，X1年7月28日甲公司向乙公司進貨，目的地交貨，甲公司於計算進貨成 本時必不受下列何者影響？', '["進貨運費", "進貨折扣", "進貨退回", "進貨折讓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00328', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '下列有關金融資產之會計處理，正確者有幾項？①採權益法認列之投資，期末不必進行公允價', '["透過其他綜合損益按公允價衡量之投資，其期末公允價值變動應列為當期損益", "按 攤銷後成本衡量之投資，期末必須以攤銷後成本表達", "透過損益按公允價值衡量之投資，其交 易成本應列為當期費用", "一項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00329', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X1年初以$500,000平價買入乙公司發行之公司債，並將其分類為按攤銷後成本衡量之 債券投資，購入時估計12個月預期信用損失金額為$6,000。X1年底評估該債券之信用風險已顯 著增加，X1年底該債券之12個月預期信用損失估計金額為$9,000，存續期間預期信用損失估計 金額為$30,000，則甲公司X1年度應認列於本期淨利之預期信用減損損失是多少？', '["$3,000", "$9,000", "$24,000", "$30,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00330', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '下列關於商譽之敘述，何者正確？', '["不得攤銷，但每年應進行減損測試", "應採有系統之方法於耐用年限內攤銷", "應儘快攤銷完畢並沖抵保留盈餘", "在認列減損損失之後，若可回收金額增加，可在已認列減損損失範圍內迴轉"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00331', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X4年7月初以$250,000購入機器設備，估計耐用年限5年，無殘值，採成本模式後續 衡量並按直線法提列折舊。X5年底由於環境改變導致有重大跡象顯示該機器之價值已經減損，該 公司於X5年底作減損測試，估計該資產公允價值減處分成本為$154,000，使用價值為$164,000， 估計耐用年限及殘值不變，則關於該設備應認列計入X5年淨利之減損損失為：', '["$0", "$11,000", "$21,000", "$31,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00332', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司之建築物部分供出租，部分供管理目的，其他資訊如下： 情境 供出租部分是否重大 供管理目的部分是否重大 各部分能否單獨出售', '["重大 重大 無法單獨出售", "重大 不重大 無法單獨出售", "不重大 重大 無法單獨出售", "重大 重大 可單獨出售 上述四種情境何者將有投資性不動產之認列？"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00333', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司銷售各式家電，並提供與同業相同之1年產品售後服務保固。針對X1年第四季之產品銷 售，估計60%無需後續維修，30%需花費$100,000維修，另10%需花費$300,000維修。該公司採 用曆年制，X1年第四季尚未有顧客要求保固。針對該季之銷售，甲公司應進行何種會計處理？', '["認列負債準備$60,000", "認列保固費用$15,000", "認列遞延保固服務收入$60,000", "認列保固服務收入$15,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00334', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '乙公司決定對某一業務線進行重組並符合負債準備之認列基準。若該業務線全部員工均接受資 遣，則公司必須支付$10,000,000；八成員工接受資遣，則公司須支付$9,000,000；六成員工接受資 遣，則公司須支付$7,000,000。依公司過去之經驗及未來預期，全部員工、八成及六成員工接受資 遣的機率分別為60%、30%及10%。則乙公司因重組而認列之負債準備金額為：', '["$10,000,000", "$9,000,000", "$7,000,000", "$9,400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00335', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '丁公司於X2年8月1日以$5,150,000之價格，發行票面利率10%，面額$5,000,000，每年7月31日 付息之公司債。下列有關丁公司公司債之敘述，何者錯誤？', '["有效利率低於票面利率", "每年認列之利息費用高於支付之現金利息", "每年12月31日應作應付利息之調整分錄", "發行之分錄可貸記應付公司債溢價"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "ec371a8ce8f0", "answer_pdf_sha1": "1751b024d1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
